### Updating useSuspenseQuery with React startTransition

Source: https://github.com/powersync-ja/powersync-js/blob/main/packages/react/README.md

Shows how to prevent `useSuspenseQuery` from suspending and showing a fallback when its query parameters change. By wrapping the state update (`setQuery`) in `React.startTransition`, React defers the update, allowing the component to keep displaying the stale data until the new data is ready, avoiding the intermediate loading state. Requires `@powersync/react`, `react`, and `react-error-boundary`.

```JSX
// TodoListDisplaySuspenseTransition.jsx
import { ErrorBoundary } from 'react-error-boundary';
import React, { Suspense } from 'react';
import { useSuspenseQuery } from '@powersync/react';

const TodoListContent = () => {
  const [query, setQuery] = React.useState('SELECT * FROM lists');
  const { data: todoLists } = useSuspenseQuery(query);

  return (
    <div>
      <button
        onClick={() => {
          React.startTransition(() => setQuery('SELECT * from lists limit 1'));
        }}>
        Update
      </button>
      <ul>
        {todoLists.map((list) => (
          <li key={list.id}>{list.name}</li>
        ))}
      </ul>
    </div>
  );
};

export const TodoListDisplaySuspense = () => {
  return (
    <ErrorBoundary fallback={<div>Something went wrong</div>}>
      <Suspense fallback={<div>Loading todo lists...</div>}>
        TodoListContent />
      </Suspense>
    </ErrorBoundary>
  );
};
```

